// Récupérer tous les items d'entrée
const items = $input.all();

// Initialiser les variables
let grandTotal = 0;
let erreur = null;

// Fonction pour vérifier si une valeur est un nombre valide et positif
function isValidPositiveNumber(value) {
  return value !== null && value !== undefined && typeof value === 'number' && !isNaN(value) && isFinite(value) && value > 0;
}

// 1. Vérifier les "Quantité" de tous les items (nombre, pas null, supérieur à 0)
let quantiteError = false;
items.forEach(item => {
  const quantite = item.json["Quantité"];
  if (!isValidPositiveNumber(quantite)) {
    quantiteError = true;
  }
});

// Si erreur sur les quantités
if (quantiteError) {
  erreur = "Erreur: Quantité";
} else {
  erreur = null;
}

// 2. Vérifier les "unitaire" de tous les items (nombre et supérieur à 0)
let unitaireError = false;
items.forEach(item => {
  const unitaire = item.json["unitaire"];
  if (!isValidPositiveNumber(unitaire)) {
    unitaireError = true;
  }
});

// 3. Si pas d'erreur sur quantité ET pas d'erreur sur unitaire → calculer Grand Total
if (erreur === null && !unitaireError) {
  items.forEach(item => {
    const petitTotal = item.json["Petit Total"];
    // Additionner les Petit Total (pas besoin de vérifier, on additionne directement)
    grandTotal += petitTotal;
  });
} else {
  grandTotal = null;
}

// Créer les items de sortie - un pour chaque item d'entrée
const outputItems = items.map((item, index) => {
  const data = item.json;

  // Vérifier si CET item spécifique a une erreur de quantité
  const quantite = data["Quantité"];
  const itemQuantiteError = !isValidPositiveNumber(quantite);

  return {
    json: {
      // Garder toutes les données originales
      ...data,
      // Ajouter les informations de validation
      "Grand Total": grandTotal,
      "Erreur": erreur,
      "Erreur item": itemQuantiteError ? "Erreur: Quantité" : null
    }
  };
});

return outputItems;

// ItemsID (robuste) — "item i" = "Quantité X unitaire$" (unitaire à 2 décimales)
// + champs additionnels par i : Criticié i, Consommable i, No Article i, Procédé i, Name item i

const rows = $input.all();
if (!rows.length) return [];

// Parse tolérant: enlève $/espaces, remplace virgule par point
const parseNum = (v) => {
  if (v === null || v === undefined || v === '') return null;
  const n = Number(String(v).replace(/\s|\$/g, '').replace(',', '.'));
  return Number.isFinite(n) ? n : null;
};

// Libellé formaté: "Quantité X unitaire$"
const fmt = (q, u) => {
  const nq = parseNum(q);
  const nu = parseNum(u);
  if (nq !== null && nu !== null) return `${nq} X ${nu.toFixed(2)}$`;
  if (nq !== null && nu === null)  return `${nq}`;
  if (nq === null && nu !== null)  return `${nu.toFixed(2)}$`;
  return 'Non spécifié';
};

// Helper pour lire une propriété tolérante (top-level ou sous "properties")
const getProp = (r, key) =>
  r.json[key] ??
  (r.json.properties && r.json.properties[key]) ??
  null;

const increment = rows.length;
const itemsID   = rows.map(r => r.json.id).filter(Boolean).join(', ');

const itemList        = {};
const lienList        = {};
const criticieList    = {};
const consommableList = {};
const noArticleList   = {};
const procedeList     = {};
const nameItemList    = {};

rows.forEach((r, i) => {
  const y    = i + 1;
  const qte  = getProp(r, 'Quantité');
  const unit = getProp(r, 'unitaire');
  const url  = getProp(r, 'URL');

  // Champs additionnels (sources)
  const criticite     = getProp(r, 'Criticité');
  const consommable   = getProp(r, '🔴Types de consommables');
  const noArticle     = getProp(r, "No d'article");
  const procede       = getProp(r, 'Procédé');
  const nomCommun     = getProp(r, 'Nom Commun');

  // Sorties
  itemList[`item ${y}`]            = fmt(qte, unit);   // "2 X 53.00$" | "2" | "53.00$" | "Non spécifié"
  lienList[`Lien ${y}`]            = url || null;

  criticieList[`Criticié ${y}`]    = criticite ?? null;
  consommableList[`Consommable ${y}`] = consommable ?? null;
  noArticleList[`No Article ${y}`] = noArticle ?? null;
  procedeList[`Procédé ${y}`]      = procede ?? null;
  nameItemList[`Name item ${y}`]   = nomCommun ?? null;
});

return [{
  json: {
    ...rows[0].json,     // base
    increment,
    ItemsID: itemsID,
    // listes
    ...itemList,
    ...lienList,
    ...criticieList,
    ...consommableList,
    ...noArticleList,
    ...procedeList,
    ...nameItemList,
  }
}];

