const end = new Date(log.finishedAt).getTime();
log.durationSec = Math.round((end - start) / 1000);

// 🎯 CORRECTION : Extraire les noms de nœuds uniques des échecs
const failedNodeNames = [];
const uniqueErrorMessages = [];

// Parcourir les actions pour identifier les échecs
if (log.actions && Array.isArray(log.actions)) {
  log.actions.forEach(action => {
    if (!action.ok) {
      // Ajouter le nom du nœud s'il n'est pas déjà présent
      if (!failedNodeNames.includes(action.node)) {
        failedNodeNames.push(action.node);
      }

      // Ajouter le message d'erreur s'il n'est pas déjà présent
      if (action.msg && !uniqueErrorMessages.includes(action.msg)) {
        uniqueErrorMessages.push(action.msg);
      }
    }
  });
}

